#include<bits/stdc++.h>
using namespace std;
int o,n,t[100001],p[100001],ans,top,m=1,yh[100001],sj[100001],k;
bool r[100001];
int main() {
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>o>>p[i]>>t[i];
		if(o==0) yh[++top]=p[i],sj[top]=t[i],ans+=p[i];
		else {
			k=0;
			for(int j=m; j<=top; j++) {
					if(r[j]) {
						continue;
					}
					if(t[i]-sj[j]>45) {
						m=j;
					} else if(yh[j]>=p[i]) {
						k=j;
						r[k]=true;
						break;
					}
				}
				if(!k) ans+=p[i];
			}
	}
	cout<<ans;
	return 0;
}
